    private func handleUniversalLink(_ url: URL) {
        guard url.scheme == "https", url.host == "myapp.com" else {
            print("Not a universal link for myapp.com: \(url)")
            return
        }

        print("Handling Universal Link: \(url.absoluteString)")

        let pathComponents = url.pathComponents.filter { $0 != "/" } // Remove empty strings from paths like /profile/123

        // Assuming your app's root is a UITabBarController or UINavigationController
        // You'll need to adapt this based on your app's navigation hierarchy.
        guard let rootViewController = window?.rootViewController else {
            print("Root view controller not available.")
            return
        }

        // Example: If your root is a Tab Bar Controller
        if let tabBarController = rootViewController as? UITabBarController {
            // Reset to a known state, e.g., first tab, before navigating
            tabBarController.selectedIndex = 0
            if let navigationController = tabBarController.selectedViewController as? UINavigationController {
                navigationController.popToRootViewController(animated: false)
                navigate(to: url, in: navigationController)
            } else {
                // If the selected tab is not a nav controller, you might need a different approach
                print("Selected tab is not a UINavigationController.")
                navigate(to: url, in: nil) // Try to navigate without a specific nav controller
            }
        }
        // Example: If your root is a UINavigationController
        else if let navigationController = rootViewController as? UINavigationController {
            navigationController.popToRootViewController(animated: false)
