    private func navigate(to url: URL, in navigationController: UINavigationController?) {
        let pathComponents = url.pathComponents.filter { !$0.isEmpty && $0 != "/" }
        print("Path components: \(pathComponents)")

        guard let firstPathComponent = pathComponents.first else {
            print("No significant path components found. Navigating to default.")
            return // Or navigate to a default screen
        }

        switch firstPathComponent {
        case "profile":
            if pathComponents.count > 1, let profileID = pathComponents[1] as String? {
                let profileVC = ProfileViewController(profileID: profileID)
                navigationController?.pushViewController(profileVC, animated: true)
                print("Navigated to Profile with ID: \(profileID)")
            } else {
                let profileListVC = ProfileListViewController()
                navigationController?.pushViewController(profileListVC, animated: true)
                print("Navigated to Profile List")
            }
        case "payment":
            if pathComponents.count > 1, pathComponents[1] == "confirm" {
                let paymentConfirmVC = PaymentConfirmationViewController()
                navigationController?.pushViewController(paymentConfirmVC, animated: true)
                print("Navigated to Payment Confirmation")
            } else {
                let paymentVC = PaymentViewController()
                navigationController?.pushViewController(paymentVC, animated: true)
                print("Navigated to Payment default")
            }
        case "admin":
            if pathComponents.count > 1, pathComponents[1] == "settings" {
                let adminSettingsVC = AdminSettingsViewController()
                navigationController?.pushViewController(adminSettingsVC, animated: true)
                print("Navigated to Admin Settings")
            } else {
                let adminDashboardVC = AdminDashboardViewController()
                navigationController?.pushViewController(adminDashboardVC, animated: true)
                print("Navigated to Admin Dashboard")
            }
        default:
            print("Unknown path component: \(firstPathComponent). Showing default view.")
            // Handle unknown paths, e.g., show an error or return to home
